import React from "react";
import "./Home.css";
import Grid from "@material-ui/core/Grid";
import Switch from "@material-ui/core/Switch";
import Slider from "@material-ui/core/Slider";
import Container from "@material-ui/core/Container";

class Home extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      state_status: true,
      brightness_status: true,
      data: this.props.data,
    };
  }

  componentDidMount() {
    this.setState({
      state_status: !!parseInt(this.state.data["STATE_STATUS"]) ? true : false,
      brightness_status: !!parseInt(this.state.data["BRIGHTNESS_STATUS"]) ? false: true,
    });
  }

  handleStatusChange(status) {
    this.setState({ state_status: status });
  }

  handleBrightnessChange(status) {
    this.setState({ brightness_status: status });
  }

  checkStatus = (e) => {
    console.log(e);
  };

  render() {
    return (
      <div className="Home">
        <Container maxWidth="xs">
          <Grid container spacing={1}>
            <Grid item xs={6}>
              Status
            </Grid>
            <p>
              The switch is{" "}
              <span>{this.state.state_status ? "on" : "off"}</span>.
            </p>
            <Grid item xs={6}>
              <Switch
                name="checkedStatus"
                color="primary"
                checked={this.state.state_status}
                onChange={(event) =>
                  this.handleStatusChange(event.currentTarget.checked)
                }
              />
            </Grid>
            <Grid item xs={12}>
              <hr></hr>
            </Grid>
            <Grid item xs={6}>
              Light Sensor
            </Grid>
            <p>
              The switch is{" "}
              <span>{this.state.brightness_status ? "on" : "off"}</span>.
            </p>
            <Grid item xs={6}>
              <Switch
                name="checkedB"
                color="primary"
                checked={this.state.brightness_status}
                onChange={(event) =>
                  this.handleBrightnessChange(event.currentTarget.checked)
                }
              />
            </Grid>
            <Grid item xs={12}>
              Brightness
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
            <Grid item xs={12}>
              <hr></hr>
            </Grid>
            <Grid item xs={12}>
              Red
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
            <Grid item xs={12}>
              Green
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
            <Grid item xs={12}>
              Blue
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
          </Grid>
        </Container>
      </div>
    );
  }
}

export default Home;
